var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SHOTGUN_SL_NULL_NULL`,text:{KOREA:`어쩐 일이십니까, 사장님.`,JPN:`いかがなさいましたか、社長。`,ENG:`What can I do for you, Boss?`,TWN:`請問有什麼事嗎，老闆。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHOTGUN_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SHOTGUN_SL_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`......`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHOTGUN_SL_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`SHOTGUN_SL_NULL_NULL`,text:{KOREA:`이런, 종신계약이라니.`,JPN:`おっと、終身契約とは。`,ENG:`Oh, a lifetime contract.`,TWN:`哎呀，竟然是終身契約。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHOTGUN_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`SHOTGUN_SL_NULL_NULL`,text:{KOREA:`파견생활 막바지엔 좀 쉬었으면 했습니다만......`,JPN:`派遣生活も終盤に差し掛かり、少しは休めそうだと思っていたのですが……`,ENG:`My deployment is almost over, so I was going to take a break afterward...`,TWN:`本來還想在派遣期的最後稍微放鬆一下......`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHOTGUN_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`SHOTGUN_SL_NULL_NULL`,text:{KOREA:`사장님이 말씀인데 제가 어떻게 못하겠단 소릴 하겠습니까.`,JPN:`社長のお申しつけとあらば、できないなどと言えるはずもありません。`,ENG:`But how can I decline your offer?`,TWN:`但既然老闆都這麼說了，我怎麼可能會拒絕呢？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHOTGUN_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`SHOTGUN_SL_NULL_NULL`,text:{KOREA:`그래도 후임들한테 못 받아본 사랑을 사장님께 듬뿍 받는 것 같아서 기분은 좋슴다.`,JPN:`後輩たちにはあまり好かれなかった気がしますが、
社長に好いていただけて嬉しい限りです。`,ENG:`I feel as if you're giving me the love that I didn't get from my juniors.`,TWN:`況且，我雖然沒有得到後輩的愛戴，但卻很受老闆的關照，所以感到很開心。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SHOTGUN_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};